import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import API from '../api';
import '../App.css';

const AdminLogin = () => {
  const [step, setStep] = useState(1); // Step 1: Login, Step 2: OTP Verification
  const [formData, setFormData] = useState({
    email: '',
    password: '',
  });
  const [otp, setOtp] = useState('');
  const [phone, setPhone] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleLoginSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // First step: Validate credentials and send OTP
      const response = await API.post('/auth/admin/login', formData);

      if (response.data.success && response.data.requiresOtp) {
        // Admin credentials are correct, now need OTP verification
        setPhone(response.data.phone); // Masked phone from backend
        alert(`OTP sent to ${response.data.phone}. Please verify.`);
        setStep(2);
      } else if (response.data.success) {
        // In case OTP is disabled, direct login
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('adminUser', JSON.stringify(response.data.admin));
        
        alert('Admin Login successful!');
        navigate('/admin/dashboard');
      }
    } catch (error) {
      console.error('Admin Login error:', error.response?.data);
      alert(error.response?.data?.message || 'Admin Login failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleOtpSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      // Verify OTP for admin
      const response = await API.post('/auth/admin/verify-otp', {
        email: formData.email,
        otp: otp
      });
      
      if (response.data.success) {
        localStorage.setItem('token', response.data.token);
        localStorage.setItem('adminUser', JSON.stringify(response.data.admin));
        
        alert('Admin verification successful!');
        navigate('/admin/dashboard');
      }
    } catch (error) {
      console.error('OTP verification error:', error.response?.data);
      alert(error.response?.data?.message || 'OTP verification failed.');
    } finally {
      setLoading(false);
    }
  };

  const handleResendOtp = async () => {
    setLoading(true);
    try {
      const response = await API.post('/auth/admin/resend-otp', {
        email: formData.email
      });
      if (response.data.success) {
        alert('OTP resent successfully!');
      }
    } catch (error) {
      alert('Failed to resend OTP. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-page" style={{ background: 'linear-gradient(135deg, #434343 0%, #000000 100%)' }}>
      <div className="login-container">
        <div style={styles.adminBadge}>
          <span style={styles.crownIcon}>👑</span> ADMIN PORTAL
        </div>
        <h2>KDMC Administrator Login</h2>
        
        {step === 1 ? (
          // Step 1: Login Form
          <>
            <form onSubmit={handleLoginSubmit}>
              <div className="form-group">
                <label>Admin Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleChange}
                  placeholder="Enter admin email"
                  required
                />
              </div>
              
              <div className="form-group">
                <label>Password</label>
                <input
                  type="password"
                  name="password"
                  value={formData.password}
                  onChange={handleChange}
                  placeholder="Enter password"
                  required
                />
              </div>
              
              <div style={styles.securityNote}>
                🔒 Two-factor authentication required
              </div>
              
              <button 
                type="submit" 
                className="login-btn" 
                disabled={loading}
                style={{ background: 'linear-gradient(135deg, #434343 0%, #000000 100%)' }}
              >
                {loading ? 'Authenticating...' : 'Secure Login'}
              </button>
            </form>
          </>
        ) : (
          // Step 2: OTP Verification
          <div style={styles.otpContainer}>
            <div style={styles.otpIcon}>🔐</div>
            <h3 style={styles.otpTitle}>Two-Factor Authentication</h3>
            <p style={styles.otpText}>
              OTP sent to registered phone<br />
              <strong>{phone}</strong>
            </p>
            
            <form onSubmit={handleOtpSubmit}>
              <div className="form-group">
                <label>Enter OTP</label>
                <input
                  type="text"
                  value={otp}
                  onChange={(e) => setOtp(e.target.value)}
                  placeholder="Enter 6-digit OTP"
                  maxLength="6"
                  pattern="[0-9]{6}"
                  style={styles.otpInput}
                  required
                />
              </div>
              
              <button 
                type="submit" 
                className="login-btn" 
                disabled={loading}
                style={{ background: 'linear-gradient(135deg, #434343 0%, #000000 100%)' }}
              >
                {loading ? 'Verifying...' : 'Verify & Login'}
              </button>
            </form>
            
            <div style={styles.resendSection}>
              <p style={styles.resendText}>Didn't receive OTP?</p>
              <button 
                onClick={handleResendOtp} 
                style={styles.resendBtn}
                disabled={loading}
              >
                Resend OTP
              </button>
            </div>
            
            <button 
              onClick={() => setStep(1)} 
              style={styles.backBtn}
            >
              ← Back to Login
            </button>
          </div>
        )}
        
        <p className="auth-footer">
          <Link to="/login">← Back to Citizen Login</Link>
        </p>
        
        <div style={styles.securityFooter}>
          <p style={styles.securityText}>
            🛡️ This is a secure admin portal. All login attempts are monitored and logged.
          </p>
        </div>
      </div>
    </div>
  );
};

const styles = {
  adminBadge: {
    background: 'linear-gradient(135deg, #ff9800 0%, #f57c00 100%)',
    color: 'white',
    padding: '10px 20px',
    borderRadius: '25px',
    textAlign: 'center',
    fontWeight: 'bold',
    fontSize: '14px',
    marginBottom: '20px',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
    gap: '8px'
  },
  crownIcon: {
    fontSize: '18px'
  },
  securityNote: {
    textAlign: 'center',
    color: '#ff9800',
    fontSize: '13px',
    marginBottom: '15px',
    fontWeight: '600'
  },
  otpContainer: {
    textAlign: 'center'
  },
  otpIcon: {
    fontSize: '60px',
    marginBottom: '20px'
  },
  otpTitle: {
    fontSize: '24px',
    fontWeight: 'bold',
    color: '#333',
    marginBottom: '10px'
  },
  otpText: {
    color: '#666',
    marginBottom: '30px',
    lineHeight: '1.6'
  },
  otpInput: {
    textAlign: 'center',
    fontSize: '24px',
    letterSpacing: '8px',
    fontWeight: 'bold'
  },
  resendSection: {
    marginTop: '20px',
    paddingTop: '20px',
    borderTop: '1px solid #f0f0f0'
  },
  resendText: {
    color: '#666',
    fontSize: '14px',
    marginBottom: '10px'
  },
  resendBtn: {
    background: 'transparent',
    border: 'none',
    color: '#ff9800',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '14px',
    textDecoration: 'underline'
  },
  backBtn: {
    marginTop: '15px',
    background: 'transparent',
    border: 'none',
    color: '#999',
    cursor: 'pointer',
    fontSize: '13px'
  },
  securityFooter: {
    marginTop: '20px',
    paddingTop: '15px',
    borderTop: '1px solid #f0f0f0'
  },
  securityText: {
    color: '#999',
    fontSize: '11px',
    textAlign: 'center',
    lineHeight: '1.5'
  }
};

export default AdminLogin;
